data.content:
MSTest **does not have** `Assert.IsGreaterThan` or `Assert.IsInRange` — those don't exist. Here's what's actually available for boundary checking:

## MSTest Comparison Options

| Need | Use |
|------|-----|
| Greater/less than | `Assert.IsTrue(value > threshold)` |
| Range check | `Assert.IsTrue(value >= lo && value <= hi)` |
| Float equality | `Assert.AreEqual(expected, actual, delta)` |
| Exceptions | `Assert.ThrowsException<T>(action)` |

## Example Tests

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Contoso.Scoring.Tests;

[TestClass]
public class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calc = new();

    [TestMethod]
    public void CalculatePercentage_PerfectScore_Returns100()
    {
        var result = _calc.CalculatePercentage(10, 10);
        Assert.AreEqual(100.0, result, 0.001);
    }

    [TestMethod]
    public void CalculatePercentage_ResultIsInValidRange()
    {
        var result = _calc.CalculatePercentage(7, 10);
        Assert.IsTrue(result >= 0.0 && result <= 100.0,
            $"Expected 0-100 but got {result}");
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(5, 0));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(11, 10));
    }

    [TestMethod]
    [DataRow(90.0, "A")]
    [DataRow(80.0, "B")]
    [DataRow(70.0, "C")]
    [DataRow(60.0, "D")]
    [DataRow(59.9, "F")]
    public void GetGrade_BoundaryValues(double pct, string expected)
    {
        Assert.AreEqual(expected, _calc.GetGrade(pct));
    }

    [TestMethod]
    public void NormalizeScore_ExceedingMax_CapsAt100()
    {
        var result = _calc.NormalizeScore(150, 100);
        Assert.AreEqual(100.0, result, 0.001);
        Assert.IsTrue(result <= 100.0, "Normalized score must not exceed 100");
    }

    [TestMethod]
    public void NormalizeScore_ResultIsNonNegative()
    {
        var result = _calc.NormalizeScore(0, 50);
        Assert.IsTrue(result >= 0.0, $"Expected non-negative but got {result}");
    }
}
```

**Key takeaway:** Use `Assert.IsTrue()` with a descriptive message for comparisons, and `Assert.AreEqual(expected, actual, delta)` for floating-point checks with tolerance. If you want richer assertion syntax, consider adding the **FluentAssertions** NuGet package which provides `result.Should().BeInRange(0, 100)`.
